1	package config
2	
3	import (
4		"encoding/hex"
5		"fmt"
6		"os"
7	)
8	
9	type Config struct {
10		ListenAddr    string
11		DatabaseURL   string
12		JWTSigningKey []byte
13		AESMasterKey  []byte
14	}
15	
16	func Load() (*Config, error) {
17		listenAddr := os.Getenv("LISTEN_ADDR")
18		if listenAddr == "" {
19			listenAddr = ":8080"
20		}
21	
22		dbURL := os.Getenv("DATABASE_URL")
23		if dbURL == "" {
24			return nil, fmt.Errorf("DATABASE_URL is required")
25		}
26	
27		jwtKey := os.Getenv("JWT_SIGNING_KEY")
28		if jwtKey == "" {
29			return nil, fmt.Errorf("JWT_SIGNING_KEY is required")
30		}
31	
32		aesHex := os.Getenv("AES_MASTER_KEY")
33		if aesHex == "" {
34			return nil, fmt.Errorf("AES_MASTER_KEY is required")
35		}
36		aesKey, err := hex.DecodeString(aesHex)
37		if err != nil {
38			return nil, fmt.Errorf("AES_MASTER_KEY must be hex-encoded: %w", err)
39		}
40		if len(aesKey) != 32 {
41			return nil, fmt.Errorf("AES_MASTER_KEY must be 32 bytes (64 hex chars), got %d bytes", len(aesKey))
42		}
43	
44		return &Config{
45			ListenAddr:    listenAddr,
46			DatabaseURL:   dbURL,
47			JWTSigningKey: []byte(jwtKey),
48			AESMasterKey:  aesKey,
49		}, nil
50	}
