1	package crypto
2	
3	import (
4		"crypto/aes"
5		"crypto/cipher"
6		"crypto/hmac"
7		"crypto/rand"
8		"crypto/sha256"
9		"fmt"
10		"io"
11	)
12	
13	type AESEncryptor struct {
14		gcm cipher.AEAD
15		key []byte
16	}
17	
18	func NewAESEncryptor(key []byte) (*AESEncryptor, error) {
19		block, err := aes.NewCipher(key)
20		if err != nil {
21			return nil, fmt.Errorf("create cipher: %w", err)
22		}
23		gcm, err := cipher.NewGCM(block)
24		if err != nil {
25			return nil, fmt.Errorf("create GCM: %w", err)
26		}
27		return &AESEncryptor{gcm: gcm, key: key}, nil
28	}
29	
30	func (e *AESEncryptor) Encrypt(plaintext []byte) ([]byte, error) {
31		nonce := make([]byte, e.gcm.NonceSize())
32		if _, err := io.ReadFull(rand.Reader, nonce); err != nil {
33			return nil, fmt.Errorf("generate nonce: %w", err)
34		}
35		return e.gcm.Seal(nonce, nonce, plaintext, nil), nil
36	}
37	
38	func (e *AESEncryptor) Decrypt(ciphertext []byte) ([]byte, error) {
39		nonceSize := e.gcm.NonceSize()
40		if len(ciphertext) < nonceSize {
41			return nil, fmt.Errorf("ciphertext too short")
42		}
43		nonce, ct := ciphertext[:nonceSize], ciphertext[nonceSize:]
44		plaintext, err := e.gcm.Open(nil, nonce, ct, nil)
45		if err != nil {
46			return nil, fmt.Errorf("decrypt: %w", err)
47		}
48		return plaintext, nil
49	}
50	
51	func (e *AESEncryptor) HMACHash(data []byte) []byte {
52		h := hmac.New(sha256.New, e.key)
53		h.Write(data)
54		return h.Sum(nil)
55	}
