1	package crypto
2	
3	import "golang.org/x/crypto/bcrypt"
4	
5	const bcryptCost = 12
6	
7	func HashPassword(password string) (string, error) {
8		hash, err := bcrypt.GenerateFromPassword([]byte(password), bcryptCost)
9		if err != nil {
10			return "", err
11		}
12		return string(hash), nil
13	}
14	
15	func CheckPassword(hash, password string) bool {
16		return bcrypt.CompareHashAndPassword([]byte(hash), []byte(password)) == nil
17	}
