1	server {
2	    listen 80;
3	    server_name _;
4	    root /usr/share/nginx/html;
5	    index index.html;
6	
7	    # API proxy
8	    location /api/ {
9	        proxy_pass http://backend:8080;
10	        proxy_set_header Host $host;
11	        proxy_set_header X-Real-IP $remote_addr;
12	        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
13	        proxy_set_header X-Forwarded-Proto $scheme;
14	
15	        # For file uploads (10MB)
16	        client_max_body_size 11m;
17	    }
18	
19	    # SPA fallback
20	    location / {
21	        try_files $uri $uri/ /index.html;
22	    }
23	
24	    # Cache static assets
25	    location ~* \.(js|css|png|jpg|jpeg|gif|ico|svg|woff|woff2|ttf|eot)$ {
26	        expires 1y;
27	        add_header Cache-Control "public, immutable";
28	    }
29	}
