41			return errorResponse(c, http.StatusUnauthorized, dto.CodeUnauthorized, "missing refresh token")
42		}
43	
44		cookies, err := h.authService.Refresh(c.Request().Context(), cookie.Value)
45		if err != nil {
46			return mapError(c, err)
47		}
48	
49		for _, cookie := range cookies {
50			c.SetCookie(cookie)
51		}
