18		uploadDir      string
19	}
20	
21	func NewMessageHandler(ms *service.MessageService, uploadDir string) *MessageHandler {
22		return &MessageHandler{messageService: ms, uploadDir: uploadDir}
23	}
24	
25	func (h *MessageHandler) List(c echo.Context) error {
26		orderID, err := uuid.Parse(c.Param("orderId"))
27		if err != nil {
28			return errorResponse(c, http.StatusBadRequest, dto.CodeValidation, "invalid order ID")
29		}
30	
31		userID, err := uuid.Parse(middleware.GetUserID(c))
32		if err != nil {
33			return errorResponse(c, http.StatusUnauthorized, dto.CodeUnauthorized, "invalid user")
34		}
35	
36		page, pageSize := pagination(c)
37		messages, total, err := h.messageService.ListByOrder(c.Request().Context(), orderID, userID, page, pageSize)
38		if err != nil {
39			return mapError(c, err)
40		}
41		return paginatedResponse(c, messages, page, pageSize, total)
42	}
43	
44	func (h *MessageHandler) Send(c echo.Context) error {
45		orderID, err := uuid.Parse(c.Param("orderId"))
46		if err != nil {
47			return errorResponse(c, http.StatusBadRequest, dto.CodeValidation, "invalid order ID")
48		}
49	
50		userID, err := uuid.Parse(middleware.GetUserID(c))
51		if err != nil {
52			return errorResponse(c, http.StatusUnauthorized, dto.CodeUnauthorized, "invalid user")
53		}
54	
55		body := c.FormValue("body")
56		if body == "" {
57			return errorResponse(c, http.StatusUnprocessableEntity, dto.CodeValidation, "message body is required")
58		}
59	
60		var attachmentPath, attachmentMime string
61		var attachmentSize int
62	
63		file, err := c.FormFile("attachment")
64		if err == nil {
65			// Server-side 10MB enforcement
66			if file.Size > service.MaxAttachmentSize {
67				return errorResponse(c, http.StatusRequestEntityTooLarge, dto.CodeAttachmentTooLarge, "attachment exceeds 10MB limit")
68			}
69	
70			src, err := file.Open()
71			if err != nil {
72				return errorResponse(c, http.StatusInternalServerError, dto.CodeInternal, "failed to read attachment")
73			}
74			defer src.Close()
75	
76			dir := filepath.Join(h.uploadDir, orderID.String())
77			if err := os.MkdirAll(dir, 0o755); err != nil {
78				return errorResponse(c, http.StatusInternalServerError, dto.CodeInternal, "failed to create upload directory")
79			}
80	
81			ext := filepath.Ext(file.Filename)
82			filename := uuid.New().String() + ext
83			dstPath := filepath.Join(dir, filename)
84	
85			dst, err := os.Create(dstPath)
86			if err != nil {
87				return errorResponse(c, http.StatusInternalServerError, dto.CodeInternal, "failed to save attachment")
88			}
89			defer dst.Close()
90	
91			if _, err := io.Copy(dst, src); err != nil {
92				return errorResponse(c, http.StatusInternalServerError, dto.CodeInternal, "failed to write attachment")
93			}
94	
95			attachmentPath = dstPath
96			attachmentSize = int(file.Size)
97			attachmentMime = file.Header.Get("Content-Type")
98		}
99	
100		msg, err := h.messageService.Send(c.Request().Context(), orderID, userID, body,
101			attachmentPath, attachmentSize, attachmentMime)
102		if err != nil {
103			return mapError(c, err)
104		}
105		return c.JSON(http.StatusCreated, msg)
106	}
