1	package middleware
2	
3	import (
4		"net"
5		"net/http"
6		"time"
7	
8		"github.com/labstack/echo/v4"
9		"github.com/ledgermint/platform/internal/cache"
10		"github.com/ledgermint/platform/internal/dto"
11		"github.com/ledgermint/platform/internal/model"
12	)
13	
14	type IPRuleProvider interface {
15		GetAllIPRules() ([]model.IPRule, error)
16	}
17	
18	func IPFilter(provider IPRuleProvider, c *cache.HotCache) echo.MiddlewareFunc {
19		return func(next echo.HandlerFunc) echo.HandlerFunc {
20			return func(ctx echo.Context) error {
21				rules, err := getCachedIPRules(provider, c)
22				if err != nil {
23					return next(ctx) // fail open if rules can't be loaded
24				}
25	
26				if len(rules) == 0 {
27					return next(ctx)
28				}
29	
30				clientIP := net.ParseIP(ctx.RealIP())
31				if clientIP == nil {
32					return next(ctx)
33				}
34	
35				// Check deny rules first
36				for _, rule := range rules {
37					_, network, err := net.ParseCIDR(rule.CIDR)
38					if err != nil {
39						continue
40					}
41					if rule.Action == "deny" && network.Contains(clientIP) {
42						return echo.NewHTTPError(http.StatusForbidden, dto.ErrorResponse{
43							Error: dto.ErrorDetail{
44								Code:      dto.CodeForbidden,
45								Message:   "IP address blocked",
46								RequestID: GetRequestID(ctx),
47							},
48						})
49					}
50				}
51	
52				// If there are allow rules, client must match at least one
53				hasAllowRules := false
54				for _, rule := range rules {
55					if rule.Action == "allow" {
56						hasAllowRules = true
57						break
58					}
59				}
60	
61				if hasAllowRules {
62					allowed := false
63					for _, rule := range rules {
64						if rule.Action != "allow" {
65							continue
66						}
67						_, network, err := net.ParseCIDR(rule.CIDR)
68						if err != nil {
69							continue
70						}
71						if network.Contains(clientIP) {
72							allowed = true
73							break
74						}
75					}
76					if !allowed {
77						return echo.NewHTTPError(http.StatusForbidden, dto.ErrorResponse{
78							Error: dto.ErrorDetail{
79								Code:      dto.CodeForbidden,
80								Message:   "IP address not in allow list",
81								RequestID: GetRequestID(ctx),
82							},
83						})
84					}
85				}
86	
87				return next(ctx)
88			}
89		}
90	}
91	
92	func getCachedIPRules(provider IPRuleProvider, c *cache.HotCache) ([]model.IPRule, error) {
93		if cached, ok := c.Get("ip_rules"); ok {
94			return cached.([]model.IPRule), nil
95		}
96		rules, err := provider.GetAllIPRules()
97		if err != nil {
98			return nil, err
99		}
100		c.Set("ip_rules", rules, 60*time.Second)
101		return rules, nil
102	}
