8	export function formatDate(dateStr: string): string {
9	  return new Date(dateStr).toLocaleDateString('en-US', {
10	    year: 'numeric',
11	    month: 'short',
12	    day: 'numeric',
13	    hour: '2-digit',
14	    minute: '2-digit',
15	  });
16	}
17	
18	/**
19	 * Formats a date as "MM/DD/YYYY h:mm AM/PM" for human-readable display
20	 * e.g. "03/25/2026 5:00 PM"
21	 */
22	export function formatDateTimeHuman(dateStr: string): string {
23	  const d = new Date(dateStr);
24	  const month = String(d.getMonth() + 1).padStart(2, '0');
25	  const day = String(d.getDate()).padStart(2, '0');
26	  const year = d.getFullYear();
27	  let hours = d.getHours();
28	  const minutes = String(d.getMinutes()).padStart(2, '0');
29	  const ampm = hours >= 12 ? 'PM' : 'AM';
30	  hours = hours % 12 || 12;
31	  return `${month}/${day}/${year} ${hours}:${minutes} ${ampm}`;
32	}
33	
34	export function formatRelativeTime(dateStr: string): string {
35	  const now = new Date();
36	  const date = new Date(dateStr);
37	  const diffMs = now.getTime() - date.getTime();
38	  const diffMins = Math.floor(diffMs / 60000);
39	
40	  if (diffMins < 1) return 'just now';
41	  if (diffMins < 60) return `${diffMins}m ago`;
42	  const diffHours = Math.floor(diffMins / 60);
43	  if (diffHours < 24) return `${diffHours}h ago`;
44	  const diffDays = Math.floor(diffHours / 24);
45	  if (diffDays < 7) return `${diffDays}d ago`;
46	  return formatDate(dateStr);
47	}
