1	const SSN_REGEX = /\b\d{3}-?\d{2}-?\d{4}\b/;
2	const PHONE_REGEX = /\b(\+?1[-.\s]?)?\(?\d{3}\)?[-.\s]?\d{3}[-.\s]?\d{4}\b/;
