8	const RequestIDKey = "request_id"
9	
10	func RequestID() echo.MiddlewareFunc {
11		return func(next echo.HandlerFunc) echo.HandlerFunc {
12			return func(c echo.Context) error {
13				id := c.Request().Header.Get("X-Request-ID")
14				if id == "" {
15					id = uuid.New().String()
16				}
17				c.Set(RequestIDKey, id)
18				c.Response().Header().Set("X-Request-ID", id)
19				return next(c)
20			}
21		}
22	}
23	
24	func GetRequestID(c echo.Context) string {
25		if id, ok := c.Get(RequestIDKey).(string); ok {
26			return id
27		}
28		return ""
29	}
