110				TestName: test.Name,
111				Variant:  variantName,
112			})
113		}
114		return assignments, nil
115	}
116	
117	// AssignVariant uses deterministic hashing: fnv32(userID + testName) % 100.
118	func AssignVariant(userID, testName string, trafficPct int) string {
119		h := fnv.New32a()
120		h.Write([]byte(userID + testName))
121		bucket := int(h.Sum32() % 100)
122		if bucket < trafficPct {
123			return "test"
124		}
125		return "control"
126	}
