2	
3	import (
4		"context"
5		"crypto/sha256"
6		"fmt"
7		"net/http"
8		"time"
9	
10		"github.com/golang-jwt/jwt/v5"
11		"github.com/google/uuid"
12		"github.com/ledgermint/platform/internal/crypto"
13		"github.com/ledgermint/platform/internal/dto"
14		"github.com/ledgermint/platform/internal/middleware"
15		"github.com/ledgermint/platform/internal/model"
16		"github.com/ledgermint/platform/internal/store"
17	)
18	
19	type AuthService struct {
20		userStore  *store.UserStore
21		signingKey []byte
22	}
23	
24	func NewAuthService(userStore *store.UserStore, signingKey []byte) *AuthService {
25		return &AuthService{userStore: userStore, signingKey: signingKey}
26	}
27	
28	func (s *AuthService) Login(ctx context.Context, req dto.LoginRequest) (*dto.AuthResponse, []*http.Cookie, error) {
29		user, err := s.userStore.GetByUsername(ctx, req.Username)
30		if err != nil {
31			return nil, nil, fmt.Errorf("lookup user: %w", err)
32		}
33		if user == nil {
34			return nil, nil, dto.ErrInvalidCredentials
35		}
36	
37		if user.IsLocked {
38			if user.LockedUntil != nil && time.Now().Before(*user.LockedUntil) {
39				return nil, nil, dto.ErrAccountLocked
40			}
41			if err := s.userStore.UnlockAccount(ctx, user.ID); err != nil {
42				return nil, nil, fmt.Errorf("unlock account: %w", err)
43			}
44		}
45	
46		if !crypto.CheckPassword(user.PasswordHash, req.Password) {
47			if err := s.userStore.IncrementFailedLogin(ctx, user.ID); err != nil {
48				return nil, nil, fmt.Errorf("increment failed login: %w", err)
49			}
50			if user.FailedLoginCount+1 >= 5 {
51				lockUntil := time.Now().Add(30 * time.Minute).Format(time.RFC3339)
52				if err := s.userStore.LockAccount(ctx, user.ID, lockUntil); err != nil {
53					return nil, nil, fmt.Errorf("lock account: %w", err)
54				}
55			}
56			return nil, nil, dto.ErrInvalidCredentials
57		}
58	
59		if err := s.userStore.ResetFailedLogin(ctx, user.ID); err != nil {
60			return nil, nil, fmt.Errorf("reset failed login: %w", err)
61		}
62	
63		userRoles, err := s.userStore.GetUserRoles(ctx, user.ID)
64		if err != nil {
65			return nil, nil, fmt.Errorf("get roles: %w", err)
66		}
67		roleNames := make([]string, len(userRoles))
68		for i, r := range userRoles {
69			roleNames[i] = r.RoleName
70		}
71	
72		accessToken, err := s.generateAccessToken(user.ID.String(), roleNames)
73		if err != nil {
74			return nil, nil, fmt.Errorf("generate access token: %w", err)
75		}
76	
77		refreshTokenStr := uuid.New().String()
78		familyID := uuid.New()
79		tokenHash := sha256.Sum256([]byte(refreshTokenStr))
80	
81		rt := &model.RefreshToken{
82			ID:        uuid.New(),
83			UserID:    user.ID,
84			TokenHash: tokenHash[:],
85			FamilyID:  familyID,
86			ExpiresAt: time.Now().Add(7 * 24 * time.Hour),
87		}
88		if err := s.userStore.CreateRefreshToken(ctx, rt); err != nil {
89			return nil, nil, fmt.Errorf("create refresh token: %w", err)
90		}
91	
92		csrfToken, err := middleware.GenerateCSRFToken()
93		if err != nil {
94			return nil, nil, fmt.Errorf("generate CSRF token: %w", err)
95		}
96	
97		cookies := []*http.Cookie{
98			{
99				Name: "access_token", Value: accessToken, Path: "/",
100				HttpOnly: true, Secure: false, SameSite: http.SameSiteStrictMode, MaxAge: 900,
101			},
102			{
103				Name: "refresh_token", Value: refreshTokenStr, Path: "/api/auth",
104				HttpOnly: true, Secure: false, SameSite: http.SameSiteStrictMode, MaxAge: 604800,
105			},
106			{
107				Name: "csrf_token", Value: csrfToken, Path: "/",
108				HttpOnly: false, Secure: false, SameSite: http.SameSiteStrictMode, MaxAge: 604800,
109			},
110		}
111	
112		resp := &dto.AuthResponse{
113			User: dto.UserResponse{
114				ID: user.ID, Username: user.Username, DisplayName: user.DisplayName,
115				IsLocked: user.IsLocked, CreatedAt: user.CreatedAt, UpdatedAt: user.UpdatedAt,
116			},
117			Roles: roleNames,
118		}
119		return resp, cookies, nil
120	}
121	
122	func (s *AuthService) Refresh(ctx context.Context, refreshTokenStr string) ([]*http.Cookie, error) {
123		tokenHash := sha256.Sum256([]byte(refreshTokenStr))
124		rt, err := s.userStore.GetRefreshTokenByHash(ctx, tokenHash[:])
125		if err != nil {
126			return nil, fmt.Errorf("lookup refresh token: %w", err)
127		}
128		if rt == nil {
129			return nil, dto.ErrUnauthorized
130		}
131	
132		if rt.RevokedAt != nil {
133			_ = s.userStore.RevokeRefreshTokenFamily(ctx, rt.FamilyID)
134			return nil, dto.ErrUnauthorized
135		}
136		if time.Now().After(rt.ExpiresAt) {
137			return nil, dto.ErrUnauthorized
138		}
139	
140		if err := s.userStore.RevokeRefreshToken(ctx, rt.ID); err != nil {
141			return nil, fmt.Errorf("revoke token: %w", err)
142		}
143	
144		user, err := s.userStore.GetByID(ctx, rt.UserID)
145		if err != nil || user == nil {
146			return nil, dto.ErrUnauthorized
147		}
148	
149		userRoles, err := s.userStore.GetUserRoles(ctx, user.ID)
150		if err != nil {
151			return nil, fmt.Errorf("get roles: %w", err)
152		}
153		roleNames := make([]string, len(userRoles))
154		for i, r := range userRoles {
155			roleNames[i] = r.RoleName
156		}
157	
158		accessToken, err := s.generateAccessToken(user.ID.String(), roleNames)
159		if err != nil {
160			return nil, fmt.Errorf("generate access token: %w", err)
161		}
162	
163		newRefreshStr := uuid.New().String()
164		newHash := sha256.Sum256([]byte(newRefreshStr))
165		newRT := &model.RefreshToken{
166			ID: uuid.New(), UserID: rt.UserID, TokenHash: newHash[:],
167			FamilyID: rt.FamilyID, ExpiresAt: time.Now().Add(7 * 24 * time.Hour),
168		}
169		if err := s.userStore.CreateRefreshToken(ctx, newRT); err != nil {
170			return nil, fmt.Errorf("create refresh token: %w", err)
171		}
172	
173		csrfToken, err := middleware.GenerateCSRFToken()
174		if err != nil {
175			return nil, fmt.Errorf("generate CSRF token: %w", err)
176		}
177	
178		cookies := []*http.Cookie{
179			{Name: "access_token", Value: accessToken, Path: "/", HttpOnly: true, Secure: false, SameSite: http.SameSiteStrictMode, MaxAge: 900},
180			{Name: "refresh_token", Value: newRefreshStr, Path: "/api/auth", HttpOnly: true, Secure: false, SameSite: http.SameSiteStrictMode, MaxAge: 604800},
181			{Name: "csrf_token", Value: csrfToken, Path: "/", HttpOnly: false, Secure: false, SameSite: http.SameSiteStrictMode, MaxAge: 604800},
182		}
183		return cookies, nil
184	}
185	
186	func (s *AuthService) Logout(ctx context.Context, userID uuid.UUID) []*http.Cookie {
187		_ = s.userStore.RevokeAllUserTokens(ctx, userID)
188		return []*http.Cookie{
189			{Name: "access_token", Value: "", Path: "/", MaxAge: -1, HttpOnly: true},
190			{Name: "refresh_token", Value: "", Path: "/api/auth", MaxAge: -1, HttpOnly: true},
191			{Name: "csrf_token", Value: "", Path: "/", MaxAge: -1},
192		}
193	}
194	
195	func (s *AuthService) generateAccessToken(userID string, roles []string) (string, error) {
196		claims := &middleware.UserClaims{
197			UserID: userID,
198			Roles:  roles,
199			RegisteredClaims: jwt.RegisteredClaims{
200				ExpiresAt: jwt.NewNumericDate(time.Now().Add(15 * time.Minute)),
201				IssuedAt:  jwt.NewNumericDate(time.Now()),
202				Issuer:    "ledgermint",
203			},
204		}
205		token := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)
206		return token.SignedString(s.signingKey)
207	}
