1	import { useState } from 'react';
2	
3	interface MaskedFieldProps {
4	  value: string;
5	  label?: string;
6	}
7	
8	export function MaskedField({ value, label }: MaskedFieldProps) {
9	  const [revealed, setRevealed] = useState(false);
10	
11	  if (!value) return null;
12	
13	  return (
14	    <div className="flex items-center gap-2">
15	      {label && <span className="text-sm text-gray-500">{label}:</span>}
16	      <span className="text-sm font-mono">{revealed ? value : maskValue(value)}</span>
17	      <button
18	        onClick={() => setRevealed(!revealed)}
19	        className="text-xs text-primary-600 hover:underline"
20	      >
21	        {revealed ? 'Hide' : 'Reveal'}
22	      </button>
23	    </div>
24	  );
25	}
26	
27	function maskValue(value: string): string {
28	  if (value.includes('@')) {
29	    const [local, domain] = value.split('@');
30	    return local[0] + '***@' + domain[0] + '***' + domain.slice(domain.lastIndexOf('.'));
31	  }
32	  if (value.length > 4) {
33	    return '***' + value.slice(-4);
34	  }
35	  return '***';
36	}
