136	func (s *UserService) GetMaskedEmail(ctx context.Context, user *model.User) string {
137		if user.EmailEncrypted == nil {
138			return ""
139		}
140		plaintext, err := s.encryptor.Decrypt(user.EmailEncrypted)
141		if err != nil {
142			return "***"
143		}
144		email := string(plaintext)
145		return maskEmail(email)
146	}
147	
148	func maskEmail(email string) string {
149		at := -1
150		for i, c := range email {
151			if c == '@' {
152				at = i
153				break
154			}
155		}
156		if at <= 0 {
157			return "***"
158		}
159		masked := string(email[0])
160		for i := 1; i < at; i++ {
161			masked += "*"
162		}
163		masked += email[at:]
164		return masked
165	}
