1	import { useState } from 'react';
2	import { useNavigate } from 'react-router-dom';
3	import { useForm } from 'react-hook-form';
4	import { z } from 'zod';
5	import { login } from '../api/auth';
6	import { useAuthStore } from '../store/authStore';
7	
8	const loginSchema = z.object({
9	  username: z
10	    .string()
11	    .min(3, 'Username must be at least 3 characters')
12	    .max(100, 'Username must be at most 100 characters'),
13	  password: z
14	    .string()
15	    .min(8, 'Password must be at least 8 characters')
16	    .max(128, 'Password must be at most 128 characters'),
17	});
18	
19	type LoginFormData = z.infer<typeof loginSchema>;
20	
21	export function LoginPage() {
22	  const [serverError, setServerError] = useState('');
23	  const [loading, setLoading] = useState(false);
24	  const { setAuth } = useAuthStore();
25	  const navigate = useNavigate();
26	
27	  const {
28	    register,
29	    handleSubmit,
30	    formState: { errors },
31	  } = useForm<LoginFormData>({
32	    mode: 'onChange',
33	    resolver: async (values) => {
34	      const result = loginSchema.safeParse(values);
35	      if (result.success) {
36	        return { values: result.data, errors: {} };
37	      }
38	      const fieldErrors: Record<string, { type: string; message: string }> = {};
39	      for (const issue of result.error.issues) {
40	        const field = issue.path[0] as string;
41	        if (!fieldErrors[field]) {
42	          fieldErrors[field] = { type: 'validation', message: issue.message };
43	        }
44	      }
45	      return { values: {}, errors: fieldErrors };
46	    },
47	  });
48	
49	  const onSubmit = async (data: LoginFormData) => {
50	    setServerError('');
51	    setLoading(true);
52	
53	    try {
54	      const { data: resp } = await login(data.username, data.password);
55	      setAuth(resp.user, resp.roles);
56	      navigate('/');
