17	func NewAuthHandler(as *service.AuthService) *AuthHandler {
18		return &AuthHandler{authService: as}
19	}
20	
21	func (h *AuthHandler) Login(c echo.Context) error {
22		var req dto.LoginRequest
23		if err := bindAndValidate(c, &req); err != nil {
24			return err
25		}
26	
27		resp, cookies, err := h.authService.Login(c.Request().Context(), req)
28		if err != nil {
29			return mapError(c, err)
30		}
31	
32		for _, cookie := range cookies {
33			c.SetCookie(cookie)
34		}
35		return c.JSON(http.StatusOK, resp)
36	}
37	
38	func (h *AuthHandler) Refresh(c echo.Context) error {
39		cookie, err := c.Cookie("refresh_token")
40		if err != nil {
41			return errorResponse(c, http.StatusUnauthorized, dto.CodeUnauthorized, "missing refresh token")
42		}
43	
44		cookies, err := h.authService.Refresh(c.Request().Context(), cookie.Value)
45		if err != nil {
46			return mapError(c, err)
47		}
48	
49		for _, cookie := range cookies {
50			c.SetCookie(cookie)
51		}
52		return c.JSON(http.StatusOK, map[string]string{"status": "ok"})
53	}
54	
55	func (h *AuthHandler) Logout(c echo.Context) error {
56		userID, err := uuid.Parse(middleware.GetUserID(c))
57		if err != nil {
58			return errorResponse(c, http.StatusUnauthorized, dto.CodeUnauthorized, "invalid user")
59		}
60	
61		cookies := h.authService.Logout(c.Request().Context(), userID)
62		for _, cookie := range cookies {
63			c.SetCookie(cookie)
64		}
65		return c.JSON(http.StatusOK, map[string]string{"status": "ok"})
66	}
