{"file_path": "/Users/macbookpro/Projects/eaglepoint/w1t21/repo/unit_tests/test_order_state_machine.py", "content": """"Unit tests for order state machine transitions."""
import unittest


# Replicate the order state machine from backend/internal/model/order.go
ALLOWED_TRANSITIONS = {
    "pending": ["confirmed", "cancelled"],
    "confirmed": ["processing", "cancelled"],
    "processing": ["completed"],
    "completed": [],
    "cancelled": [],
}

ALL_STATUSES = ["pending", "confirmed", "processing", "completed", "cancelled"]


def can_transition(from_status, to_status):
    return to_status in ALLOWED_TRANSITIONS.get(from_status, [])


class TestOrderStateMachine(unittest.TestCase):
    """Tests for order state transitions matching backend/internal/model/order.go."""

    # --- Valid transitions ---

    def test_pending_to_confirmed(self):
        self.assertTrue(can_transition("pending", "confirmed"))

    def test_pending_to_cancelled(self):
        self.assertTrue(can_transition("pending", "cancelled"))

    def test_confirmed_to_processing(self):
        self.assertTrue(can_transition("confirmed", "processing"))

    def test_confirmed_to_cancelled(self):
        self.assertTrue(can_transition("confirmed", "cancelled"))

    def test_processing_to_completed(self):
        self.assertTrue(can_transition("processing", "completed"))

    # --- Invalid transitions ---

    def test_pending_cannot_skip_to_processing(self):
        self.assertFalse(can_transition("pending", "processing"))

    def test_pending_cannot_skip_to_completed(self):
        self.assertFalse(can_transition("pending", "completed"))

    def test_processing_cannot_be_cancelled(self):
        self.assertFalse(can_transition("processing", "cancelled"))

    def test_completed_is_terminal(self):
        for status in ALL_STATUSES:
            self.assertFalse(
                can_transition("completed", status),
                f"completed should not transition to {status}",
            )

    def test_cancelled_is_terminal(self):
        for status in ALL_STATUSES:
            self.assertFalse(
                can_transition("cancelled", status),
                f"cancelled should not transition to {status}",
            )

    def test_self_transitions_are_invalid(self):
        for status in ALL_STATUSES:
            self.assertFalse(
                can_transition(status, status),
                f"{status} should not transition to itself",
            )

    def test_backward_transitions_invalid(self):
        self.assertFalse(can_transition("confirmed", "pending"))
        self.assertFalse(can_transition("processing", "confirmed"))
        self.assertFalse(can_transition("processing", "pending"))
        self.assertFalse(can_transition("completed", "processing"))

    # --- Boundary conditions ---

    def test_unknown_status_has_no_transitions(self):
        self.assertFalse(can_transition("unknown_status", "pending"))

    def test_all_statuses_have_transition_entries(self):
        for status in ALL_STATUSES:
            self.assertIn(status, ALLOWED_TRANSITIONS)

    def test_happy_path_full_lifecycle(self):
        """Verify the complete happy path: pending -> confirmed -> processing -> completed."""
        path = ["pending", "confirmed", "processing", "completed"]
        for i in range(len(path) - 1):
            self.assertTrue(
                can_transition(path[i], path[i + 1]),
                f"Should transition from {path[i]} to {path[i+1]}",
            )

    def test_cancellation_path_from_pending(self):
        self.assertTrue(can_transition("pending", "cancelled"))

    def test_cancellation_path_from_confirmed(self):
        self.assertTrue(can_transition("confirmed", "cancelled"))

    def test_transition_targets_are_valid_statuses(self):
        for from_status, targets in ALLOWED_TRANSITIONS.items():
            for target in targets:
                self.assertIn(
                    target,
                    ALL_STATUSES,
                    f"Transition target '{target}' from '{from_status}' is not a valid status",
                )


if __name__ == "__main__":
    unittest.main()
"}

