import unittest


def format_cents(cents, currency="USD"):
    """Replicate formatCents from frontend/src/utils/formatters.ts."""
    amount = cents / 100
    if currency == "USD":
        return f"${amount:,.2f}"
    return f"{amount:,.2f} {currency}"


def mask_value(value):
    """Replicate maskValue from frontend/src/components/shared/MaskedField.tsx."""
    if "@" in value:
        parts = value.split("@")
        local = parts[0]
        domain = parts[1]
        last_dot = domain.rfind(".")
        return local[0] + "***@" + domain[0] + "***" + domain[last_dot:]
    if len(value) > 4:
        return "***" + value[-4:]
    return "***"


class TestFormatCents(unittest.TestCase):

    def test_basic_price(self):
        self.assertEqual(format_cents(9990), "$99.90")

    def test_zero(self):
        self.assertEqual(format_cents(0), "$0.00")

    def test_one_cent(self):
        self.assertEqual(format_cents(1), "$0.01")

    def test_one_dollar(self):
        self.assertEqual(format_cents(100), "$1.00")

    def test_large_price(self):
        result = format_cents(249900)
        self.assertEqual(result, "$2,499.00")

    def test_sub_dollar(self):
        self.assertEqual(format_cents(50), "$0.50")

    def test_negative_price(self):
        result = format_cents(-100)
        self.assertEqual(result, "-$1.00")

    def test_seed_data_prices(self):
        self.assertEqual(format_cents(99900), "$999.00")
        self.assertEqual(format_cents(249900), "$2,499.00")
        self.assertEqual(format_cents(49900), "$499.00")


class TestMaskValue(unittest.TestCase):

    def test_mask_email(self):
        result = mask_value("alice@example.com")
        self.assertEqual(result, "a***@e***.com")

    def test_mask_short_email(self):
        result = mask_value("a@b.co")
        self.assertEqual(result, "a***@b***.co")

    def test_mask_long_value(self):
        result = mask_value("1234567890")
        self.assertEqual(result, "***7890")

    def test_mask_short_value(self):
        result = mask_value("ab")
        self.assertEqual(result, "***")

    def test_mask_exactly_four_chars(self):
        result = mask_value("abcd")
        self.assertEqual(result, "***")

    def test_mask_five_chars(self):
        result = mask_value("abcde")
        self.assertEqual(result, "***bcde")


class TestAccountLockout(unittest.TestCase):
    """Test account lockout logic from backend/internal/service/auth_service.go."""

    MAX_FAILED_ATTEMPTS = 5
    LOCKOUT_DURATION_MINUTES = 30

    def test_under_threshold_not_locked(self):
        for i in range(self.MAX_FAILED_ATTEMPTS - 1):
            self.assertFalse(i + 1 >= self.MAX_FAILED_ATTEMPTS)

    def test_at_threshold_locked(self):
        self.assertTrue(self.MAX_FAILED_ATTEMPTS >= self.MAX_FAILED_ATTEMPTS)

    def test_over_threshold_locked(self):
        self.assertTrue(6 >= self.MAX_FAILED_ATTEMPTS)

    def test_lockout_duration(self):
        self.assertEqual(self.LOCKOUT_DURATION_MINUTES, 30)


