import unittest


def format_cents(cents, currency="USD"):
    """Replicate formatCents from frontend/src/utils/formatters.ts."""
    amount = cents / 100
    if currency == "USD":
        return f"${amount:,.2f}"
    return f"{amount:,.2f} {currency}"


def mask_value(value):
    """Replicate maskValue from frontend/src/components/shared/MaskedField.tsx."""
    if "@" in value:
        parts = value.split("@")
        local = parts[0]
        domain = parts[1]
        last_dot = domain.rfind(".")
        return local[0] + "***@" + domain[0] + "***" + domain[last_dot:]
    if len(value) > 4:
        return "***" + value[-4:]
    return "***"


class TestFormatCents(unittest.TestCase):

    def test_basic_price(self):
        self.assertEqual(format_cents(9990), "$99.90")

    def test_zero(self):
        self.assertEqual(format_cents(0), "$0.00")

    def test_one_cent(self):
        self.assertEqual(format_cents(1), "$0.01")

    def test_one_dollar(self):
        self.assertEqual(format_cents(100), "$1.00")

    def test_large_price(self):
        result = format_cents(249900)
        self.assertEqual(result, "$2,499.00")

    def test_sub_dollar(self):
        self.assertEqual(format_cents(50), "$0.50")

    def test_negative_price(self):
        result = format_cents(-100)
        self.assertEqual(result, "-$1.00")

    def test_seed_data_prices(self):
        self.assertEqual(format_cents(99900), "$999.00")
        self.assertEqual(format_cents(249900), "$2,499.00")
        self.assertEqual(format_cents(49900), "$499.00")


