    "ERR_ORDER_DUPLICATE": 409,
    "ERR_INVALID_TRANSITION": 422,
    "ERR_OVERSOLD": 409,
    "ERR_INTERNAL": 500,
}

# HTTP status code to error code mapping for validation
HTTP_STATUS_ERRORS = {
    400: "bad request",
    401: "unauthorized",
    403: "forbidden",
    404: "not found",
    409: "conflict",
    413: "entity too large",
    422: "unprocessable entity",
    423: "locked",
    429: "too many requests",
    500: "internal server error",
}


class TestErrorCodeMapping(unittest.TestCase):
    """Tests for error code to HTTP status code mapping from handler/helpers.go."""

    def test_not_found_maps_to_404(self):
        self.assertEqual(ERROR_CODES["ERR_NOT_FOUND"], 404)

    def test_forbidden_maps_to_403(self):
        self.assertEqual(ERROR_CODES["ERR_FORBIDDEN"], 403)

    def test_unauthorized_maps_to_401(self):
        self.assertEqual(ERROR_CODES["ERR_UNAUTHORIZED"], 401)

    def test_conflict_maps_to_409(self):
        self.assertEqual(ERROR_CODES["ERR_CONFLICT"], 409)

    def test_rate_limited_maps_to_429(self):
        self.assertEqual(ERROR_CODES["ERR_RATE_LIMITED"], 429)

    def test_validation_maps_to_422(self):
        self.assertEqual(ERROR_CODES["ERR_VALIDATION"], 422)

    def test_account_locked_maps_to_423(self):
        self.assertEqual(ERROR_CODES["ERR_ACCOUNT_LOCKED"], 423)

    def test_invalid_credentials_maps_to_401(self):
        self.assertEqual(ERROR_CODES["ERR_INVALID_CREDENTIALS"], 401)

    def test_attachment_too_large_maps_to_413(self):
        self.assertEqual(ERROR_CODES["ERR_ATTACHMENT_TOO_LARGE"], 413)

    def test_duplicate_order_maps_to_409(self):
        self.assertEqual(ERROR_CODES["ERR_ORDER_DUPLICATE"], 409)

    def test_invalid_transition_maps_to_422(self):
        self.assertEqual(ERROR_CODES["ERR_INVALID_TRANSITION"], 422)

    def test_oversold_maps_to_409(self):
        self.assertEqual(ERROR_CODES["ERR_OVERSOLD"], 409)

    def test_internal_maps_to_500(self):
        self.assertEqual(ERROR_CODES["ERR_INTERNAL"], 500)

    def test_all_error_codes_have_valid_http_status(self):
        valid_codes = {400, 401, 403, 404, 409, 413, 422, 423, 429, 500}
        for code, status in ERROR_CODES.items():
            self.assertIn(
                status,
                valid_codes,
                f"Error code {code} maps to unexpected HTTP status {status}",
            )


class TestErrorResponseStructure(unittest.TestCase):
    """Test that error responses follow the documented JSON structure."""

    def test_error_envelope_structure(self):
        sample = {
            "error": {
                "code": "ERR_NOT_FOUND",
                "message": "not found",
                "request_id": "abc-123",
            }
        }
        self.assertIn("error", sample)
