                f"Error code {code} should start with ERR_",
            )

    def test_error_codes_are_uppercase(self):
        for code in ERROR_CODES:
            self.assertEqual(
                code,
                code.upper(),
                f"Error code {code} should be uppercase",
            )


class TestRoleAuthorization(unittest.TestCase):
    """Test role-based access control rules from router/router.go."""

    ROUTE_ROLES = {
        "/api/users": ["administrator"],
        "/api/collectibles/mine": ["seller"],
        "/api/collectibles (POST)": ["seller"],
        "/api/collectibles/:id/hide": ["administrator"],
        "/api/collectibles/:id/publish": ["administrator"],
        "/api/orders (POST)": ["buyer"],
        "/api/orders/:id/confirm": ["seller"],
        "/api/orders/:id/process": ["seller"],
        "/api/orders/:id/complete": ["seller"],
        "/api/orders/:id/fulfillment": ["seller"],
        "/api/analytics": ["administrator", "compliance_analyst"],
        "/api/ab-tests": ["administrator"],
        "/api/admin/ip-rules": ["administrator"],
        "/api/admin/anomalies": ["administrator", "compliance_analyst"],
    }

    def test_user_management_requires_admin(self):
        self.assertEqual(self.ROUTE_ROLES["/api/users"], ["administrator"])

    def test_listing_creation_requires_seller(self):
        self.assertEqual(self.ROUTE_ROLES["/api/collectibles (POST)"], ["seller"])

    def test_order_creation_requires_buyer(self):
        self.assertEqual(self.ROUTE_ROLES["/api/orders (POST)"], ["buyer"])

    def test_order_confirmation_requires_seller(self):
        self.assertEqual(self.ROUTE_ROLES["/api/orders/:id/confirm"], ["seller"])

    def test_analytics_allows_admin_and_compliance(self):
        roles = self.ROUTE_ROLES["/api/analytics"]
        self.assertIn("administrator", roles)
        self.assertIn("compliance_analyst", roles)

    def test_ab_tests_admin_only(self):
        self.assertEqual(self.ROUTE_ROLES["/api/ab-tests"], ["administrator"])

    def test_moderation_requires_admin(self):
        self.assertEqual(self.ROUTE_ROLES["/api/collectibles/:id/hide"], ["administrator"])
        self.assertEqual(self.ROUTE_ROLES["/api/collectibles/:id/publish"], ["administrator"])

    def test_anomalies_allows_admin_and_compliance(self):
        roles = self.ROUTE_ROLES["/api/admin/anomalies"]
        self.assertIn("administrator", roles)
        self.assertIn("compliance_analyst", roles)


if __name__ == "__main__":
    unittest.main()
"}

