11	
12	func CSRF() echo.MiddlewareFunc {
13		return func(next echo.HandlerFunc) echo.HandlerFunc {
14			return func(c echo.Context) error {
15				// Skip for safe methods
16				if c.Request().Method == http.MethodGet ||
17					c.Request().Method == http.MethodHead ||
18					c.Request().Method == http.MethodOptions {
19					return next(c)
20				}
21	
22				// Skip CSRF for login and refresh (pre-auth)
23				path := c.Request().URL.Path
24				if path == "/api/auth/login" || path == "/api/auth/refresh" {
25					return next(c)
26				}
27	
28				cookie, err := c.Cookie("csrf_token")
29				if err != nil {
30					return echo.NewHTTPError(http.StatusForbidden, dto.ErrorResponse{
31						Error: dto.ErrorDetail{
32							Code:      dto.CodeForbidden,
33							Message:   "missing CSRF cookie",
34							RequestID: GetRequestID(c),
35						},
36					})
37				}
38	
39				header := c.Request().Header.Get("X-CSRF-Token")
40				if header == "" || header != cookie.Value {
41					return echo.NewHTTPError(http.StatusForbidden, dto.ErrorResponse{
42						Error: dto.ErrorDetail{
43							Code:      dto.CodeForbidden,
44							Message:   "CSRF token mismatch",
45							RequestID: GetRequestID(c),
46						},
47					})
48				}
49	
50				return next(c)
51			}
52		}
53	}
54	
55	func GenerateCSRFToken() (string, error) {
56		b := make([]byte, 32)
57		if _, err := rand.Read(b); err != nil {
58			return "", err
59		}
60		return hex.EncodeToString(b), nil
61	}
62	
63	func SetCSRFCookie(c echo.Context, token string) {
64		c.SetCookie(&http.Cookie{
65			Name:     "csrf_token",
66			Value:    token,
67			Path:     "/",
68			HttpOnly: false, // Must be readable by JS
69			Secure:   false, // LAN - no TLS
70			SameSite: http.SameSiteStrictMode,
71		})
72	}
