1	package middleware
2	
3	import (
4		"net/http"
5		"strings"
6	
7		"github.com/golang-jwt/jwt/v5"
8		"github.com/labstack/echo/v4"
9		"github.com/ledgermint/platform/internal/dto"
10	)
11	
12	type UserClaims struct {
13		UserID string   `json:"user_id"`
14		Roles  []string `json:"roles"`
15		jwt.RegisteredClaims
16	}
17	
18	func JWTAuth(signingKey []byte) echo.MiddlewareFunc {
19		return func(next echo.HandlerFunc) echo.HandlerFunc {
20			return func(c echo.Context) error {
21				cookie, err := c.Cookie("access_token")
22				if err != nil {
23					return echo.NewHTTPError(http.StatusUnauthorized, dto.ErrorResponse{
24						Error: dto.ErrorDetail{
25							Code:      dto.CodeUnauthorized,
26							Message:   "missing access token",
27							RequestID: GetRequestID(c),
28						},
29					})
30				}
31	
32				token, err := jwt.ParseWithClaims(cookie.Value, &UserClaims{}, func(t *jwt.Token) (interface{}, error) {
33					return signingKey, nil
34				})
35				if err != nil || !token.Valid {
36					return echo.NewHTTPError(http.StatusUnauthorized, dto.ErrorResponse{
37						Error: dto.ErrorDetail{
38							Code:      dto.CodeUnauthorized,
39							Message:   "invalid or expired token",
40							RequestID: GetRequestID(c),
41						},
42					})
43				}
44	
45				claims, ok := token.Claims.(*UserClaims)
46				if !ok {
47					return echo.NewHTTPError(http.StatusUnauthorized, dto.ErrorResponse{
48						Error: dto.ErrorDetail{
49							Code:      dto.CodeUnauthorized,
50							Message:   "invalid token claims",
51							RequestID: GetRequestID(c),
52						},
53					})
54				}
55	
56				c.Set("user_id", claims.UserID)
57				c.Set("user_roles", claims.Roles)
58				return next(c)
59			}
60		}
61	}
62	
63	func RequireRole(roles ...string) echo.MiddlewareFunc {
64		return func(next echo.HandlerFunc) echo.HandlerFunc {
65			return func(c echo.Context) error {
66				userRoles, ok := c.Get("user_roles").([]string)
67				if !ok {
68					return echo.NewHTTPError(http.StatusForbidden, dto.ErrorResponse{
69						Error: dto.ErrorDetail{
70							Code:      dto.CodeForbidden,
71							Message:   "access denied",
72							RequestID: GetRequestID(c),
73						},
74					})
75				}
76	
77				for _, required := range roles {
78					for _, has := range userRoles {
79						if strings.EqualFold(required, has) {
80							return next(c)
81						}
82					}
83				}
84	
85				return echo.NewHTTPError(http.StatusForbidden, dto.ErrorResponse{
86					Error: dto.ErrorDetail{
87						Code:      dto.CodeForbidden,
88						Message:   "insufficient role",
89						RequestID: GetRequestID(c),
90					},
91				})
92			}
93		}
94	}
95	
96	func GetUserID(c echo.Context) string {
97		if id, ok := c.Get("user_id").(string); ok {
98			return id
99		}
100		return ""
101	}
102	
103	func GetUserRoles(c echo.Context) []string {
104		if roles, ok := c.Get("user_roles").([]string); ok {
105			return roles
106		}
107		return nil
108	}
