84		if user == nil {
85			return nil, dto.ErrNotFound
86		}
87	
88		if req.DisplayName != nil {
89			user.DisplayName = *req.DisplayName
90		}
91		if req.Password != nil {
92			hash, err := crypto.HashPassword(*req.Password)
93			if err != nil {
94				return nil, fmt.Errorf("hash password: %w", err)
95			}
96			user.PasswordHash = hash
97		}
98		if req.Email != nil {
99			encrypted, err := s.encryptor.Encrypt([]byte(*req.Email))
100			if err != nil {
101				return nil, fmt.Errorf("encrypt email: %w", err)
102			}
103			user.EmailEncrypted = encrypted
104			user.EmailHash = s.encryptor.HMACHash([]byte(*req.Email))
105		}
106	
107		if err := s.userStore.Update(ctx, user); err != nil {
108			return nil, fmt.Errorf("update user: %w", err)
109		}
110		return user, nil
111	}
