1	package worker
2	
3	import (
4		"context"
5		"time"
6	
7		"go.uber.org/zap"
8	)
9	
10	type Job struct {
11		Name     string
12		Interval time.Duration
13		Fn       func(ctx context.Context) error
14	}
15	
16	type Scheduler struct {
17		logger *zap.Logger
18		jobs   []Job
19	}
20	
21	func NewScheduler(logger *zap.Logger) *Scheduler {
22		return &Scheduler{logger: logger}
23	}
24	
25	func (s *Scheduler) Register(job Job) {
26		s.jobs = append(s.jobs, job)
27	}
28	
29	func (s *Scheduler) Start(ctx context.Context) {
30		for _, job := range s.jobs {
31			go s.runJob(ctx, job)
32		}
33	}
34	
35	func (s *Scheduler) runJob(ctx context.Context, job Job) {
36		ticker := time.NewTicker(job.Interval)
37		defer ticker.Stop()
38	
39		s.logger.Info("worker started", zap.String("job", job.Name), zap.Duration("interval", job.Interval))
40	
41		for {
42			select {
43			case <-ctx.Done():
44				s.logger.Info("worker stopped", zap.String("job", job.Name))
45				return
46			case <-ticker.C:
47				if err := job.Fn(ctx); err != nil {
48					s.logger.Error("worker job failed", zap.String("job", job.Name), zap.Error(err))
49				}
50			}
51		}
52	}
