96	func (s *ABTestService) GetAssignments(ctx context.Context, userID string) ([]dto.ABTestAssignment, error) {
97		tests, err := s.analyticsStore.ListRunningABTests(ctx)
98		if err != nil {
99			return nil, err
100		}
101	
102		assignments := make([]dto.ABTestAssignment, 0, len(tests))
103		for _, test := range tests {
104			variant := AssignVariant(userID, test.Name, test.TrafficPct)
105			variantName := test.ControlVariant
106			if variant == "test" {
107				variantName = test.TestVariant
108			}
109			assignments = append(assignments, dto.ABTestAssignment{
110				TestName: test.Name,
111				Variant:  variantName,
112			})
113		}
114		return assignments, nil
115	}
116	
117	// AssignVariant uses deterministic hashing: fnv32(userID + testName) % 100.
118	func AssignVariant(userID, testName string, trafficPct int) string {
119		h := fnv.New32a()
120		h.Write([]byte(userID + testName))
121		bucket := int(h.Sum32() % 100)
122		if bucket < trafficPct {
123			return "test"
124		}
125		return "control"
126	}
