3	import (
4		"context"
5		"fmt"
6		"time"
7	
8		"github.com/ledgermint/platform/internal/store"
9		"go.uber.org/zap"
10	)
11	
12	func NotificationRetryJob(notifStore *store.NotificationStore, logger *zap.Logger) Job {
13		return Job{
14			Name:     "notification_retry",
15			Interval: 60 * time.Second,
16			Fn: func(ctx context.Context) error {
17				failed, err := notifStore.GetFailedForRetry(ctx, 50)
18				if err != nil {
19					return fmt.Errorf("get failed notifications: %w", err)
20				}
21	
22				for _, n := range failed {
23					newRetryCount := n.RetryCount + 1
24					// Exponential backoff: 1min, 2min, 4min...
25					backoff := time.Duration(1<<uint(newRetryCount)) * time.Minute
26					nextRetry := time.Now().Add(backoff).Format(time.RFC3339)
27	
28					status := "delivered"
29					var nextRetryPtr *string
30					if newRetryCount >= n.MaxRetries {
31						status = "failed" // Permanently failed
32					} else {
33						nextRetryPtr = &nextRetry
34					}
35	
36					if err := notifStore.UpdateRetryState(ctx, n.ID, status, newRetryCount, nextRetryPtr); err != nil {
37						logger.Error("retry notification failed", zap.String("id", n.ID.String()), zap.Error(err))
38					}
39				}
40				return nil
41			},
42		}
43	}
