1	package service
2	
3	import (
4		"context"
5		"encoding/json"
6		"fmt"
7	
8		"github.com/google/uuid"
9		"github.com/ledgermint/platform/internal/dto"
10		"github.com/ledgermint/platform/internal/model"
11		"github.com/ledgermint/platform/internal/store"
12	)
13	
14	type OrderService struct {
15		orderStore       *store.OrderStore
16		collectibleStore *store.CollectibleStore
17		notifService     *NotificationService
18		analyticsStore   *store.AnalyticsStore
19	}
20	
21	func NewOrderService(os *store.OrderStore, cs *store.CollectibleStore, ns *NotificationService, as *store.AnalyticsStore) *OrderService {
22		return &OrderService{orderStore: os, collectibleStore: cs, notifService: ns, analyticsStore: as}
23	}
24	
25	func (s *OrderService) Create(ctx context.Context, req dto.CreateOrderRequest, buyerID uuid.UUID, idempotencyKey string) (*model.Order, error) {
26		existing, err := s.orderStore.GetByIdempotencyKey(ctx, idempotencyKey)
27		if err != nil {
28			return nil, fmt.Errorf("check idempotency: %w", err)
29		}
30		if existing != nil {
31			return existing, nil
32		}
33	
34		collectible, err := s.collectibleStore.GetByID(ctx, req.CollectibleID)
35		if err != nil {
36			return nil, fmt.Errorf("get collectible: %w", err)
37		}
38		if collectible == nil {
39			return nil, dto.ErrNotFound
40		}
41		if collectible.Status != "published" {
42			return nil, dto.ErrNotFound
43		}
44		if collectible.SellerID == buyerID {
45			return nil, fmt.Errorf("%w: cannot buy your own collectible", dto.ErrValidation)
46		}
47	
48		tx, err := s.orderStore.BeginTx(ctx)
49		if err != nil {
50			return nil, fmt.Errorf("begin tx: %w", err)
51		}
52		defer tx.Rollback(ctx)
53	
54		if err := s.orderStore.AcquireAdvisoryLock(ctx, tx, req.CollectibleID); err != nil {
55			return nil, fmt.Errorf("acquire lock: %w", err)
56		}
57	
58		hasActive, err := s.orderStore.HasActiveOrder(ctx, tx, req.CollectibleID)
59		if err != nil {
60			return nil, fmt.Errorf("check active orders: %w", err)
61		}
62		if hasActive {
63			return nil, dto.ErrOversold
64		}
65	
66		order := &model.Order{
67			IdempotencyKey:     idempotencyKey,
68			BuyerID:            buyerID,
69			CollectibleID:      req.CollectibleID,
70			SellerID:           collectible.SellerID,
71			Status:             model.OrderStatusPending,
72			PriceSnapshotCents: collectible.PriceCents,
73		}
74	
75		if err := s.orderStore.CreateInTx(ctx, tx, order); err != nil {
76			return nil, fmt.Errorf("create order: %w", err)
77		}
78	
79		transition := &model.OrderStateTransition{
80			OrderID:    order.ID,
81			FromStatus: "",
82			ToStatus:   model.OrderStatusPending,
83			ActorID:    buyerID,
84			Reason:     "order created",
85		}
86		if err := s.orderStore.RecordTransitionInTx(ctx, tx, transition); err != nil {
87			return nil, fmt.Errorf("record transition: %w", err)
88		}
89	
90		if err := tx.Commit(ctx); err != nil {
91			return nil, fmt.Errorf("commit: %w", err)
92		}
93	
94		// Emit analytics event
95		s.emitEvent(ctx, &buyerID, "order_created", &req.CollectibleID)
96	
97		return order, nil
98	}
99	
100	// GetByID with object-level authorization: only buyer or seller of the order can view it.
101	func (s *OrderService) GetByID(ctx context.Context, id uuid.UUID, actorID uuid.UUID) (*model.Order, error) {
102		order, err := s.orderStore.GetByID(ctx, id)
103		if err != nil {
104			return nil, err
105		}
106		if order == nil {
107			return nil, dto.ErrNotFound
108		}
109		if order.BuyerID != actorID && order.SellerID != actorID {
110			return nil, dto.ErrForbidden
111		}
112		return order, nil
113	}
114	
115	// TransitionStatus with object-level authorization.
116	// Confirm/Process/Complete: only the seller of THIS order.
117	// Cancel: only the buyer or seller of THIS order.
118	func (s *OrderService) TransitionStatus(ctx context.Context, orderID uuid.UUID, targetStatus model.OrderStatus, actorID uuid.UUID, reason string) (*model.Order, error) {
119		order, err := s.orderStore.GetByID(ctx, orderID)
120		if err != nil {
121			return nil, err
122		}
123		if order == nil {
124			return nil, dto.ErrNotFound
125		}
126	
127		// Object-level authorization
128		switch targetStatus {
129		case model.OrderStatusConfirmed, model.OrderStatusProcessing, model.OrderStatusCompleted:
130			if order.SellerID != actorID {
131				return nil, fmt.Errorf("%w: only the seller of this order can perform this action", dto.ErrForbidden)
132			}
133		case model.OrderStatusCancelled:
134			if order.BuyerID != actorID && order.SellerID != actorID {
135				return nil, fmt.Errorf("%w: only the buyer or seller of this order can cancel it", dto.ErrForbidden)
136			}
137		}
138	
139		if !order.Status.CanTransitionTo(targetStatus) {
140			return nil, fmt.Errorf("%w: cannot transition from %s to %s", dto.ErrInvalidTransition, order.Status, targetStatus)
141		}
142	
143		if targetStatus == model.OrderStatusCancelled {
144			if err := s.orderStore.Cancel(ctx, orderID, reason, actorID); err != nil {
145				return nil, fmt.Errorf("cancel order: %w", err)
146			}
147			s.emitEvent(ctx, &actorID, "order_cancelled", &order.CollectibleID)
148		} else {
149			if err := s.orderStore.UpdateStatus(ctx, orderID, targetStatus); err != nil {
150				return nil, fmt.Errorf("update status: %w", err)
151			}
152		}
153	
154		transition := &model.OrderStateTransition{
155			OrderID:    orderID,
156			FromStatus: order.Status,
157			ToStatus:   targetStatus,
158			ActorID:    actorID,
159			Reason:     reason,
160		}
161		if err := s.orderStore.RecordTransition(ctx, transition); err != nil {
162			return nil, fmt.Errorf("record transition: %w", err)
163		}
164	
165		s.sendOrderNotification(ctx, order, targetStatus, reason)
166	
167		order.Status = targetStatus
168		return order, nil
169	}
170	
171	func (s *OrderService) sendOrderNotification(ctx context.Context, order *model.Order, status model.OrderStatus, reason string) {
172		if s.notifService == nil {
173			return
174		}
175	
176		slugMap := map[model.OrderStatus]string{
177			model.OrderStatusConfirmed:  "order_confirmed",
178			model.OrderStatusProcessing: "order_processing",
179			model.OrderStatusCompleted:  "order_completed",
180			model.OrderStatusCancelled:  "order_cancelled",
181		}
182	
183		slug, ok := slugMap[status]
184		if !ok {
185			return
186		}
187	
188		params := map[string]string{
189			"OrderID": order.ID.String(),
190			"Reason":  reason,
191		}
192		paramsJSON, _ := json.Marshal(params)
193	
194		go func() {
195			_ = s.notifService.Send(context.Background(), order.BuyerID, slug, paramsJSON)
196		}()
197	}
198	
199	// UpdateFulfillment with object-level authorization: only the seller of this order.
200	func (s *OrderService) UpdateFulfillment(ctx context.Context, orderID uuid.UUID, req dto.UpdateFulfillmentRequest, actorID uuid.UUID) error {
201		order, err := s.orderStore.GetByID(ctx, orderID)
202		if err != nil {
203			return err
204		}
205		if order == nil {
206			return dto.ErrNotFound
207		}
208		if order.SellerID != actorID {
209			return fmt.Errorf("%w: only the seller of this order can update fulfillment", dto.ErrForbidden)
210		}
211	
212		tracking, _ := json.Marshal(req)
213		return s.orderStore.UpdateFulfillment(ctx, orderID, tracking)
214	}
215	
216	func (s *OrderService) ListByBuyer(ctx context.Context, buyerID uuid.UUID, page, pageSize int) ([]model.Order, int, error) {
217		return s.orderStore.ListByBuyer(ctx, buyerID, page, pageSize)
218	}
219	
220	func (s *OrderService) ListBySeller(ctx context.Context, sellerID uuid.UUID, page, pageSize int) ([]model.Order, int, error) {
221		return s.orderStore.ListBySeller(ctx, sellerID, page, pageSize)
222	}
223	
224	func (s *OrderService) CountOpenByBuyer(ctx context.Context, buyerID uuid.UUID) (int, error) {
225		return s.orderStore.CountOpenByBuyer(ctx, buyerID)
226	}
227	
228	func (s *OrderService) emitEvent(ctx context.Context, userID *uuid.UUID, eventType string, collectibleID *uuid.UUID) {
229		if s.analyticsStore == nil {
230			return
231		}
232		go func() {
233			_ = s.analyticsStore.RecordEvent(context.Background(), &model.AnalyticsEvent{
234				UserID:        userID,
235				EventType:     eventType,
236				CollectibleID: collectibleID,
237				SessionID:     "server",
238			})
239		}()
240	}
