26	func (s *CollectibleService) Create(ctx context.Context, req dto.CreateCollectibleRequest, sellerID uuid.UUID) (*model.Collectible, error) {
27		currency := req.Currency
28		if currency == "" {
29			currency = "USD"
30		}
31	
32		tokenID := uuid.New().String()
33		chainID := 1
34	
35		c := &model.Collectible{
36			SellerID:        sellerID,
37			Title:           req.Title,
38			Description:     req.Description,
39			ContractAddress: req.ContractAddress,
40			ChainID:         chainID,
41			TokenID:         tokenID,
42			MetadataURI:     req.MetadataURI,
43			ImageURL:        req.ImageURL,
44			PriceCents:      req.PriceCents,
45			Currency:        currency,
46		}
47	
48		if err := s.collectibleStore.Create(ctx, c); err != nil {
49			if strings.Contains(err.Error(), "idx_collectibles_identity") || strings.Contains(err.Error(), "duplicate key") {
