58	// GetByID returns a collectible. Hidden collectibles are only visible to admin/compliance roles.
59	func (s *CollectibleService) GetByID(ctx context.Context, id uuid.UUID, viewerRoles []string) (*model.Collectible, error) {
60		cacheKey := "collectible:" + id.String()
61		if cached, ok := s.cache.Get(cacheKey); ok {
62			c := cached.(*model.Collectible)
63			if c.Status == "hidden" && !hasAdminOrCompliance(viewerRoles) {
64				return nil, dto.ErrNotFound
65			}
66			return c, nil
67		}
68	
69		c, err := s.collectibleStore.GetByID(ctx, id)
70		if err != nil {
71			return nil, err
72		}
73		if c == nil {
74			return nil, dto.ErrNotFound
75		}
76	
77		// Hidden collectibles only visible to admin/compliance
78		if c.Status == "hidden" && !hasAdminOrCompliance(viewerRoles) {
79			return nil, dto.ErrNotFound
80		}
81	
82		s.cache.Set(cacheKey, c, 2*time.Minute)
83	
84		// Emit item_view event and increment view count async
85		go func() {
86			_ = s.collectibleStore.IncrementViewCount(context.Background(), id)
87		}()
88	
89		return c, nil
90	}
