94		if s.analyticsStore == nil {
95			return
96		}
97		go func() {
98			_ = s.analyticsStore.RecordEvent(context.Background(), &model.AnalyticsEvent{
99				UserID:        userID,
100				EventType:     "item_view",
101				CollectibleID: &collectibleID,
102				SessionID:     "server",
103			})
104		}()
105	}
