107	// List returns collectibles. Non-admin users can only see published.
108	func (s *CollectibleService) List(ctx context.Context, status string, page, pageSize int, viewerRoles []string) ([]model.Collectible, int, error) {
109		// Non-admin/compliance users can ONLY see published
110		if !hasAdminOrCompliance(viewerRoles) {
111			status = "published"
112		}
113	
114		cacheKey := fmt.Sprintf("collectibles:%s:%d:%d", status, page, pageSize)
115		if cached, ok := s.cache.Get(cacheKey); ok {
116			result := cached.(*cachedList)
117			return result.items, result.total, nil
118		}
119	
120		items, total, err := s.collectibleStore.List(ctx, status, page, pageSize)
121		if err != nil {
122			return nil, 0, err
123		}
124	
125		s.cache.Set(cacheKey, &cachedList{items: items, total: total}, 30*time.Second)
126	
127		// Emit catalog_view event async
128		if s.analyticsStore != nil {
129			go func() {
130				_ = s.analyticsStore.RecordEvent(context.Background(), &model.AnalyticsEvent{
131					EventType: "catalog_view",
132					SessionID: "server",
133				})
134			}()
135		}
136	
137		return items, total, nil
138	}
