90	func (s *ABTestService) GetAssignments(ctx context.Context, userID string) ([]dto.ABTestAssignment, error) {
91		tests, err := s.analyticsStore.ListRunningABTests(ctx)
92		if err != nil {
93			return nil, err
94		}
95	
96		assignments := make([]dto.ABTestAssignment, 0, len(tests))
97		for _, test := range tests {
98			variant := AssignVariant(userID, test.Name, test.TrafficPct)
99			variantName := test.ControlVariant
100			if variant == "test" {
101				variantName = test.TestVariant
102			}
103			assignments = append(assignments, dto.ABTestAssignment{
104				TestName: test.Name,
105				Variant:  variantName,
106			})
107		}
108		return assignments, nil
109	}
110	
111	// parseFlexibleDate accepts datetime-local (2006-01-02T15:04), RFC3339, and US format.
112	func parseFlexibleDate(s string) (time.Time, error) {
113		formats := []string{
114			"2006-01-02T15:04",       // HTML datetime-local
115			time.RFC3339,             // Standard API format
116			"2006-01-02T15:04:05",   // ISO without timezone
117			"01/02/2006 3:04 PM",    // US human-readable
118		}
119		for _, f := range formats {
120			if t, err := time.Parse(f, s); err == nil {
121				return t, nil
122			}
123		}
124		return time.Time{}, fmt.Errorf("unrecognized date format: %s", s)
125	}
126	
127	// AssignVariant uses deterministic hashing: fnv32(userID + testName) % 100.
128	func AssignVariant(userID, testName string, trafficPct int) string {
129		h := fnv.New32a()
130		h.Write([]byte(userID + testName))
131		bucket := int(h.Sum32() % 100)
132		if bucket < trafficPct {
133			return "test"
134		}
135		return "control"
136	}
