13	type NotificationStore struct {
14		pool *pgxpool.Pool
15	}
16	
17	func NewNotificationStore(pool *pgxpool.Pool) *NotificationStore {
18		return &NotificationStore{pool: pool}
19	}
20	
21	func (s *NotificationStore) GetTemplateBySlug(ctx context.Context, slug string) (*model.NotificationTemplate, error) {
22		var t model.NotificationTemplate
23		err := s.pool.QueryRow(ctx,
24			`SELECT id, slug, title_template, body_template, created_at
25			 FROM notification_templates WHERE slug = $1`, slug).Scan(
26			&t.ID, &t.Slug, &t.TitleTemplate, &t.BodyTemplate, &t.CreatedAt)
27		if err == pgx.ErrNoRows {
28			return nil, nil
29		}
30		return &t, err
31	}
32	
33	func (s *NotificationStore) ListTemplates(ctx context.Context) ([]model.NotificationTemplate, error) {
34		rows, err := s.pool.Query(ctx,
35			`SELECT id, slug, title_template, body_template, created_at FROM notification_templates ORDER BY slug`)
36		if err != nil {
37			return nil, err
38		}
39		defer rows.Close()
40	
41		var templates []model.NotificationTemplate
42		for rows.Next() {
43			var t model.NotificationTemplate
44			if err := rows.Scan(&t.ID, &t.Slug, &t.TitleTemplate, &t.BodyTemplate, &t.CreatedAt); err != nil {
45				return nil, err
46			}
47			templates = append(templates, t)
48		}
49		return templates, nil
50	}
51	
52	func (s *NotificationStore) Create(ctx context.Context, n *model.Notification) error {
53		return s.pool.QueryRow(ctx,
54			`INSERT INTO notifications (user_id, template_id, params, rendered_title, rendered_body, status, delivered_at)
55			 VALUES ($1, $2, $3, $4, $5, $6, CASE WHEN $6 = 'delivered' THEN NOW() ELSE NULL END)
56			 RETURNING id, created_at`,
57			n.UserID, n.TemplateID, n.Params, n.RenderedTitle, n.RenderedBody, n.Status,
58		).Scan(&n.ID, &n.CreatedAt)
59	}
60	
61	func (s *NotificationStore) GetByID(ctx context.Context, id uuid.UUID) (*model.Notification, error) {
62		var n model.Notification
63		err := s.pool.QueryRow(ctx,
64			`SELECT n.id, n.user_id, n.template_id, t.slug, n.params, n.rendered_title, n.rendered_body,
65			        n.is_read, n.status, n.retry_count, n.max_retries, n.next_retry_at, n.delivered_at, n.created_at
66			 FROM notifications n JOIN notification_templates t ON n.template_id = t.id
67			 WHERE n.id = $1`, id).Scan(
68			&n.ID, &n.UserID, &n.TemplateID, &n.TemplateSlug, &n.Params, &n.RenderedTitle, &n.RenderedBody,
69			&n.IsRead, &n.Status, &n.RetryCount, &n.MaxRetries, &n.NextRetryAt, &n.DeliveredAt, &n.CreatedAt,
70		)
71		if err == pgx.ErrNoRows {
72			return nil, nil
73		}
74		return &n, err
75	}
76	
77	func (s *NotificationStore) ListByUser(ctx context.Context, userID uuid.UUID, unreadOnly bool, page, pageSize int) ([]model.Notification, int, error) {
78		filter := ""
79		if unreadOnly {
80			filter = " AND n.is_read = FALSE"
81		}
82	
83		var total int
84		err := s.pool.QueryRow(ctx,
85			`SELECT COUNT(*) FROM notifications n WHERE n.user_id = $1`+filter, userID).Scan(&total)
86		if err != nil {
87			return nil, 0, err
88		}
89	
90		offset := (page - 1) * pageSize
91		rows, err := s.pool.Query(ctx,
92			`SELECT n.id, n.user_id, n.template_id, t.slug, n.params, n.rendered_title, n.rendered_body,
93			        n.is_read, n.status, n.retry_count, n.max_retries, n.next_retry_at, n.delivered_at, n.created_at
94			 FROM notifications n JOIN notification_templates t ON n.template_id = t.id
95			 WHERE n.user_id = $1`+filter+`
96			 ORDER BY n.created_at DESC LIMIT $2 OFFSET $3`, userID, pageSize, offset)
97		if err != nil {
98			return nil, 0, err
99		}
100		defer rows.Close()
101	
102		var notifications []model.Notification
103		for rows.Next() {
104			var n model.Notification
105			if err := rows.Scan(&n.ID, &n.UserID, &n.TemplateID, &n.TemplateSlug, &n.Params,
106				&n.RenderedTitle, &n.RenderedBody, &n.IsRead, &n.Status, &n.RetryCount,
107				&n.MaxRetries, &n.NextRetryAt, &n.DeliveredAt, &n.CreatedAt); err != nil {
108				return nil, 0, err
109			}
110			notifications = append(notifications, n)
111		}
112		return notifications, total, nil
113	}
114	
115	func (s *NotificationStore) MarkRead(ctx context.Context, id uuid.UUID) error {
116		_, err := s.pool.Exec(ctx,
117			`UPDATE notifications SET is_read = TRUE WHERE id = $1`, id)
118		return err
119	}
120	
121	func (s *NotificationStore) MarkAllRead(ctx context.Context, userID uuid.UUID) error {
122		_, err := s.pool.Exec(ctx,
123			`UPDATE notifications SET is_read = TRUE WHERE user_id = $1 AND is_read = FALSE`, userID)
124		return err
125	}
126	
127	func (s *NotificationStore) CountUnread(ctx context.Context, userID uuid.UUID) (int, error) {
128		var count int
129		err := s.pool.QueryRow(ctx,
130			`SELECT COUNT(*) FROM notifications WHERE user_id = $1 AND is_read = FALSE`, userID).Scan(&count)
131		return count, err
132	}
133	
134	func (s *NotificationStore) RetryNotification(ctx context.Context, id uuid.UUID) error {
135		_, err := s.pool.Exec(ctx,
136			`UPDATE notifications SET status = 'delivered', delivered_at = NOW(), retry_count = retry_count + 1
137			 WHERE id = $1`, id)
138		return err
139	}
140	
141	func (s *NotificationStore) GetPendingForDelivery(ctx context.Context, limit int) ([]model.Notification, error) {
142		rows, err := s.pool.Query(ctx,
143			`SELECT id, user_id, template_id, rendered_title, rendered_body, status, retry_count, max_retries
144			 FROM notifications
145			 WHERE status = 'pending'
146			 ORDER BY created_at ASC
147			 LIMIT $1`, limit)
148		if err != nil {
149			return nil, err
150		}
151		defer rows.Close()
152	
153		var notifications []model.Notification
154		for rows.Next() {
155			var n model.Notification
156			if err := rows.Scan(&n.ID, &n.UserID, &n.TemplateID, &n.RenderedTitle, &n.RenderedBody,
157				&n.Status, &n.RetryCount, &n.MaxRetries); err != nil {
158				return nil, err
159			}
160			notifications = append(notifications, n)
161		}
162		return notifications, nil
163	}
164	
165	func (s *NotificationStore) GetFailedForRetry(ctx context.Context, limit int) ([]model.Notification, error) {
166		rows, err := s.pool.Query(ctx,
167			`SELECT id, user_id, template_id, rendered_title, rendered_body, status, retry_count, max_retries
168			 FROM notifications
169			 WHERE status = 'failed' AND retry_count < max_retries AND (next_retry_at IS NULL OR next_retry_at <= NOW())
170			 LIMIT $1`, limit)
171		if err != nil {
172			return nil, err
173		}
174		defer rows.Close()
175	
176		var notifications []model.Notification
177		for rows.Next() {
178			var n model.Notification
179			if err := rows.Scan(&n.ID, &n.UserID, &n.TemplateID, &n.RenderedTitle, &n.RenderedBody,
180				&n.Status, &n.RetryCount, &n.MaxRetries); err != nil {
181				return nil, err
182			}
183			notifications = append(notifications, n)
184		}
185		return notifications, nil
186	}
187	
188	func (s *NotificationStore) UpdateRetryState(ctx context.Context, id uuid.UUID, status string, retryCount int, nextRetryAt *string) error {
189		_, err := s.pool.Exec(ctx,
190			`UPDATE notifications SET status = $2, retry_count = $3, next_retry_at = $4::timestamptz,
191			        delivered_at = CASE WHEN $2 = 'delivered' THEN NOW() ELSE delivered_at END
192			 WHERE id = $1`, id, status, retryCount, nextRetryAt)
193		return err
194	}
195	
196	// Preferences
197	
198	func (s *NotificationStore) GetPreferences(ctx context.Context, userID uuid.UUID) (*model.NotificationPreferences, error) {
199		var p model.NotificationPreferences
200		err := s.pool.QueryRow(ctx,
201			`SELECT user_id, preferences FROM notification_preferences WHERE user_id = $1`, userID).Scan(
202			&p.UserID, &p.Preferences)
203		if err == pgx.ErrNoRows {
204			return &model.NotificationPreferences{UserID: userID, Preferences: json.RawMessage(`{}`)}, nil
205		}
206		return &p, err
207	}
208	
209	func (s *NotificationStore) UpsertPreferences(ctx context.Context, userID uuid.UUID, prefs json.RawMessage) error {
210		_, err := s.pool.Exec(ctx,
211			`INSERT INTO notification_preferences (user_id, preferences)
212			 VALUES ($1, $2)
213			 ON CONFLICT (user_id) DO UPDATE SET preferences = $2`,
214			userID, prefs)
215		return err
216	}
