10	  const { user, hasRole } = useAuthStore();
11	  const queryClient = useQueryClient();
12	  const [cancelReason, setCancelReason] = useState('');
13	  const [showCancel, setShowCancel] = useState(false);
14	
15	  const { data: order, isLoading } = useQuery({
16	    queryKey: ['order', id],
17	    queryFn: () => getOrder(id!).then((r) => r.data),
18	    enabled: !!id,
19	  });
20	
21	  const transitionMutation = useMutation({
22	    mutationFn: (action: string) => {
23	      switch (action) {
24	        case 'confirm': return confirmOrder(id!);
25	        case 'process': return processOrder(id!);
26	        case 'complete': return completeOrder(id!);
27	        case 'cancel': return cancelOrder(id!, cancelReason);
28	        default: throw new Error('Unknown action');
29	      }
30	    },
31	    onSuccess: () => {
32	      queryClient.invalidateQueries({ queryKey: ['order', id] });
33	      queryClient.invalidateQueries({ queryKey: ['orders'] });
34	      setShowCancel(false);
35	    },
36	  });
37	
38	  if (isLoading) return <p className="text-gray-500">Loading...</p>;
39	  if (!order) return <p className="text-gray-500">Order not found.</p>;
40	
41	  const isSeller = order.seller_id === user?.id;
42	  const isBuyer = order.buyer_id === user?.id;
43	
44	  return (
45	    <div className="max-w-3xl mx-auto">
46	      <Link to="/orders" className="text-sm text-primary-600 hover:underline mb-4 block">Back to Orders</Link>
