53	          </div>
54	          <span className={`px-3 py-1 rounded-full text-sm font-medium ${
55	            order.status === 'completed' ? 'bg-green-100 text-green-800' :
56	            order.status === 'cancelled' ? 'bg-red-100 text-red-800' :
57	            'bg-blue-100 text-blue-800'
58	          }`}>
59	            {order.status}
60	          </span>
61	        </div>
62	
63	        <div className="grid grid-cols-2 gap-4 mb-6">
64	          <div>
65	            <p className="text-sm text-gray-500">Price</p>
66	            <p className="text-2xl font-bold text-primary-700">{formatCents(order.price_snapshot_cents)}</p>
67	          </div>
68	          <div>
69	            <p className="text-sm text-gray-500">Collectible</p>
70	            <Link to={`/catalog/${order.collectible_id}`} className="text-primary-600 hover:underline text-sm">
