80	          </div>
81	        )}
82	
83	        {order.cancellation_reason && (
84	          <div className="mb-6 p-4 bg-red-50 rounded">
85	            <p className="text-sm text-red-700">Cancellation reason: {order.cancellation_reason}</p>
86	          </div>
