88	
89	        {/* Actions */}
90	        <div className="flex gap-2 flex-wrap">
91	          {isSeller && order.status === 'pending' && (
92	            <button onClick={() => transitionMutation.mutate('confirm')} className="px-4 py-2 bg-blue-600 text-white rounded text-sm hover:bg-blue-700">
93	              Confirm Order
94	            </button>
95	          )}
96	          {isSeller && order.status === 'confirmed' && (
97	            <button onClick={() => transitionMutation.mutate('process')} className="px-4 py-2 bg-purple-600 text-white rounded text-sm hover:bg-purple-700">
98	              Start Processing
99	            </button>
100	          )}
101	          {isSeller && order.status === 'processing' && (
102	            <button onClick={() => transitionMutation.mutate('complete')} className="px-4 py-2 bg-green-600 text-white rounded text-sm hover:bg-green-700">
103	              Mark Completed
104	            </button>
105	          )}
106	          {(isBuyer || isSeller) && ['pending', 'confirmed'].includes(order.status) && (
107	            <button onClick={() => setShowCancel(true)} className="px-4 py-2 bg-red-100 text-red-700 rounded text-sm hover:bg-red-200">
108	              Cancel Order
109	            </button>
110	          )}
111	          <Link to={`/orders/${id}/messages`} className="px-4 py-2 bg-gray-100 text-gray-700 rounded text-sm hover:bg-gray-200">
112	            Messages
113	          </Link>
114	        </div>
115	
116	        {showCancel && (
117	          <div className="mt-4 p-4 bg-red-50 rounded">
118	            <textarea
119	              value={cancelReason}
120	              onChange={(e) => setCancelReason(e.target.value)}
121	              placeholder="Reason for cancellation..."
122	              className="w-full p-2 border rounded mb-2"
123	              rows={2}
124	            />
125	            <div className="flex gap-2">
126	              <button onClick={() => transitionMutation.mutate('cancel')} disabled={!cancelReason} className="px-3 py-1 bg-red-600 text-white rounded text-sm disabled:opacity-50">
