14	func AnomalyDetectorJob(orderStore *store.OrderStore, analyticsStore *store.AnalyticsStore, logger *zap.Logger) Job {
15		return Job{
16			Name:     "anomaly_detector",
17			Interval: 5 * time.Minute,
18			Fn: func(ctx context.Context) error {
19				// Rule 1: More than 6 cancellations in 24 hours
20				if err := detectExcessiveCancellations(ctx, orderStore, analyticsStore, logger); err != nil {
21					logger.Error("excessive cancellations check failed", zap.Error(err))
22				}
23	
24				// Rule 2: More than 10 failed checkout attempts in 1 hour
25				if err := detectCheckoutFailures(ctx, analyticsStore, logger); err != nil {
26					logger.Error("checkout failures check failed", zap.Error(err))
27				}
28	
29				return nil
30			},
31		}
32	}
33	
34	func detectExcessiveCancellations(ctx context.Context, orderStore *store.OrderStore, analyticsStore *store.AnalyticsStore, logger *zap.Logger) error {
35		// Get users who have cancelled orders in the last 24 hours
36		// We check all users with recent cancellations
37		rows, err := orderStore.CountByStatus(ctx)
38		if err != nil {
39			return err
40		}
41		_ = rows // Using this as a health check
42	
43		// Query users with excessive cancellations directly
44		type userCancel struct {
45			UserID string
46			Count  int
47		}
48	
49		// This is done via a direct query through the order store
50		// For each user who has cancelled, check their count
51		// In practice, we'd add a specific store method, but for now we rely on the
52		// analytics events approach - each cancellation is also an analytics event
53		users, err := analyticsStore.GetDistinctUsersWithEvents(ctx, "order_cancelled", 24)
54		if err != nil {
55			return fmt.Errorf("get users with cancellations: %w", err)
56		}
57	
58		for _, userID := range users {
59			count, err := orderStore.CountCancelledInPeriod(ctx, userID, 24)
60			if err != nil {
61				continue
62			}
63			if count > 6 {
64				details, _ := json.Marshal(map[string]interface{}{
65					"cancellations_24h": count,
66					"threshold":         6,
67				})
68				anomaly := &model.AnomalyEvent{
69					UserID:      userID,
70					AnomalyType: "excessive_cancellations",
71					Details:     details,
72				}
73				if err := analyticsStore.CreateAnomalyEvent(ctx, anomaly); err != nil {
74					logger.Error("create anomaly event failed", zap.Error(err))
75				} else {
76					logger.Warn("anomaly detected: excessive cancellations",
77						zap.String("user_id", userID.String()),
78						zap.Int("count", count))
79				}
80			}
81		}
82		return nil
83	}
84	
85	func detectCheckoutFailures(ctx context.Context, analyticsStore *store.AnalyticsStore, logger *zap.Logger) error {
86		users, err := analyticsStore.GetDistinctUsersWithEvents(ctx, "checkout_failure", 1)
87		if err != nil {
88			return fmt.Errorf("get users with checkout failures: %w", err)
89		}
90	
91		for _, userID := range users {
92			count, err := analyticsStore.CountCheckoutFailures(ctx, userID, 1)
93			if err != nil {
94				continue
95			}
96			if count > 10 {
97				details, _ := json.Marshal(map[string]interface{}{
98					"checkout_failures_1h": count,
99					"threshold":            10,
100				})
101				anomaly := &model.AnomalyEvent{
102					UserID:      userID,
103					AnomalyType: "repeated_checkout_failures",
104					Details:     details,
105				}
106				if err := analyticsStore.CreateAnomalyEvent(ctx, anomaly); err != nil {
107					logger.Error("create anomaly event failed", zap.Error(err))
108				} else {
109					logger.Warn("anomaly detected: repeated checkout failures",
110						zap.String("user_id", userID.String()),
111						zap.Int("count", count))
112				}
113			}
114		}
115		return nil
116	}
