23	func (s *ABTestService) Create(ctx context.Context, req dto.CreateABTestRequest, createdBy uuid.UUID) (*model.ABTest, error) {
24		startDate, err := parseFlexibleDate(req.StartDate)
25		if err != nil {
26			return nil, fmt.Errorf("%w: invalid start_date format, use RFC3339 or YYYY-MM-DDTHH:MM", dto.ErrValidation)
27		}
28		endDate, err := parseFlexibleDate(req.EndDate)
29		if err != nil {
30			return nil, fmt.Errorf("%w: invalid end_date format, use RFC3339 or YYYY-MM-DDTHH:MM", dto.ErrValidation)
31		}
32	
33		test := &model.ABTest{
34			Name:                 req.Name,
35			Description:          req.Description,
36			Status:               model.ABTestStatusDraft,
37			TrafficPct:           req.TrafficPct,
38			StartDate:            startDate,
39			EndDate:              endDate,
40			ControlVariant:       req.ControlVariant,
41			TestVariant:          req.TestVariant,
42			RollbackThresholdPct: req.RollbackThresholdPct,
43			CreatedBy:            createdBy,
44		}
45	
46		// Auto-start if start date is in the past or now
47		if !startDate.After(time.Now()) {
48			test.Status = model.ABTestStatusRunning
49		}
50	
51		if err := s.analyticsStore.CreateABTest(ctx, test); err != nil {
52			return nil, fmt.Errorf("create A/B test: %w", err)
53		}
