97		notif, err := s.notifStore.GetByID(ctx, id)
98		if err != nil {
99			return err
100		}
101		if notif == nil {
102			return dto.ErrNotFound
103		}
104		if notif.UserID != userID {
105			return dto.ErrForbidden
106		}
107		if notif.Status != "failed" {
