27		if err != nil {
28			return nil, fmt.Errorf("check idempotency: %w", err)
29		}
30		if existing != nil {
31			return existing, nil
32		}
33	
34		collectible, err := s.collectibleStore.GetByID(ctx, req.CollectibleID)
35		if err != nil {
36			return nil, fmt.Errorf("get collectible: %w", err)
37		}
38		if collectible == nil {
39			return nil, dto.ErrNotFound
40		}
41		if collectible.Status != "published" {
42			return nil, dto.ErrNotFound
43		}
44		if collectible.SellerID == buyerID {
45			return nil, fmt.Errorf("%w: cannot buy your own collectible", dto.ErrValidation)
46		}
47	
48		tx, err := s.orderStore.BeginTx(ctx)
49		if err != nil {
50			return nil, fmt.Errorf("begin tx: %w", err)
51		}
52		defer tx.Rollback(ctx)
53	
54		if err := s.orderStore.AcquireAdvisoryLock(ctx, tx, req.CollectibleID); err != nil {
55			return nil, fmt.Errorf("acquire lock: %w", err)
56		}
57	
58		hasActive, err := s.orderStore.HasActiveOrder(ctx, tx, req.CollectibleID)
59		if err != nil {
60			return nil, fmt.Errorf("check active orders: %w", err)
61		}
62		if hasActive {
