70			SellerID:           collectible.SellerID,
71			Status:             model.OrderStatusPending,
72			PriceSnapshotCents: collectible.PriceCents,
73		}
74	
75		if err := s.orderStore.CreateInTx(ctx, tx, order); err != nil {
76			return nil, fmt.Errorf("create order: %w", err)
77		}
78	
79		transition := &model.OrderStateTransition{
