118	func (s *OrderService) TransitionStatus(ctx context.Context, orderID uuid.UUID, targetStatus model.OrderStatus, actorID uuid.UUID, reason string) (*model.Order, error) {
119		order, err := s.orderStore.GetByID(ctx, orderID)
120		if err != nil {
121			return nil, err
122		}
123		if order == nil {
124			return nil, dto.ErrNotFound
125		}
126	
127		// Object-level authorization
128		switch targetStatus {
129		case model.OrderStatusConfirmed, model.OrderStatusProcessing, model.OrderStatusCompleted:
130			if order.SellerID != actorID {
131				return nil, fmt.Errorf("%w: only the seller of this order can perform this action", dto.ErrForbidden)
132			}
133		case model.OrderStatusCancelled:
134			if order.BuyerID != actorID && order.SellerID != actorID {
135				return nil, fmt.Errorf("%w: only the buyer or seller of this order can cancel it", dto.ErrForbidden)
136			}
137		}
138	
139		if !order.Status.CanTransitionTo(targetStatus) {
140			return nil, fmt.Errorf("%w: cannot transition from %s to %s", dto.ErrInvalidTransition, order.Status, targetStatus)
141		}
142	
143		if targetStatus == model.OrderStatusCancelled {
144			if err := s.orderStore.Cancel(ctx, orderID, reason, actorID); err != nil {
145				return nil, fmt.Errorf("cancel order: %w", err)
146			}
147			s.emitEvent(ctx, &actorID, "order_cancelled", &order.CollectibleID)
148		} else {
149			if err := s.orderStore.UpdateStatus(ctx, orderID, targetStatus); err != nil {
150				return nil, fmt.Errorf("update status: %w", err)
151			}
152		}
153	
154		transition := &model.OrderStateTransition{
155			OrderID:    orderID,
156			FromStatus: order.Status,
157			ToStatus:   targetStatus,
158			ActorID:    actorID,
159			Reason:     reason,
160		}
161		if err := s.orderStore.RecordTransition(ctx, transition); err != nil {
162			return nil, fmt.Errorf("record transition: %w", err)
163		}
164	
165		s.sendOrderNotification(ctx, order, targetStatus, reason)
166	
167		order.Status = targetStatus
168		return order, nil
169	}
