CREATE OR REPLACE FUNCTION prevent_tx_history_mutation() RETURNS TRIGGER AS $$
BEGIN
    RAISE EXCEPTION 'collectible_tx_history is append-only: updates and deletes are not allowed';
    RETURN NULL;
END;
$$ LANGUAGE plpgsql;

