1	import { useState, useEffect } from 'react';
2	import { useNavigate, useParams } from 'react-router-dom';
3	import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
4	import { createCollectible, getCollectible, updateCollectible } from '../api/collectibles';
5	
6	export function CollectibleFormPage() {
7	  const { id } = useParams<{ id: string }>();
8	  const isEdit = !!id;
9	  const navigate = useNavigate();
10	  const queryClient = useQueryClient();
11	
12	  const [form, setForm] = useState({
13	    title: '',
14	    description: '',
15	    price_cents: 0,
16	    currency: 'USD',
17	    contract_address: '',
18	    chain_id: 0,
19	    token_id: '',
20	    metadata_uri: '',
21	    image_url: '',
22	  });
23	  const [error, setError] = useState('');
24	
25	  const { data: editData } = useQuery({
26	    queryKey: ['collectible', id],
27	    queryFn: () => getCollectible(id!).then((r) => r.data),
28	    enabled: isEdit,
29	  });
30	
31	  useEffect(() => {
32	    if (editData) {
33	      const c = editData.collectible;
34	      setForm({
35	        title: c.title,
36	        description: c.description,
37	        price_cents: c.price_cents,
38	        currency: c.currency,
39	        contract_address: c.contract_address || '',
40	        metadata_uri: c.metadata_uri || '',
41	        image_url: c.image_url || '',
42	      });
43	    }
44	  }, [editData]);
45	
46	  const createMutation = useMutation({
47	    mutationFn: () => createCollectible({
48	      ...form,
49	      price_cents: Number(form.price_cents),
50	      chain_id: form.chain_id || undefined,
51	      token_id: form.token_id || undefined,
52	    }),
53	    onSuccess: (res) => {
54	      queryClient.invalidateQueries({ queryKey: ['collectibles'] });
55	      navigate(`/catalog/${res.data.id}`);
56	    },
57	    onError: (err: any) => setError(err.response?.data?.error?.message || 'Failed'),
58	  });
59	
60	  const updateMutation = useMutation({
61	    mutationFn: () => updateCollectible(id!, {
62	      title: form.title,
63	      description: form.description,
64	      price_cents: Number(form.price_cents),
65	      image_url: form.image_url,
66	      metadata_uri: form.metadata_uri,
67	    }),
68	    onSuccess: () => {
69	      queryClient.invalidateQueries({ queryKey: ['collectible', id] });
70	      navigate(`/catalog/${id}`);
71	    },
72	    onError: (err: any) => setError(err.response?.data?.error?.message || 'Failed'),
73	  });
74	
75	  const handleSubmit = (e: React.FormEvent) => {
76	    e.preventDefault();
77	    if (isEdit) updateMutation.mutate();
78	    else createMutation.mutate();
79	  };
80	
81	  return (
82	    <div className="max-w-2xl mx-auto">
83	      <h1 className="text-2xl font-bold mb-6">{isEdit ? 'Edit Listing' : 'Create Listing'}</h1>
84	
85	      <form onSubmit={handleSubmit} className="bg-white rounded-lg shadow-sm border p-6 space-y-4">
86	        <div>
87	          <label className="block text-sm font-medium text-gray-700 mb-1">Title *</label>
88	          <input type="text" value={form.title} onChange={(e) => setForm({ ...form, title: e.target.value })}
89	            className="w-full px-3 py-2 border rounded focus:ring-2 focus:ring-primary-500" required maxLength={300} />
90	        </div>
91	        <div>
92	          <label className="block text-sm font-medium text-gray-700 mb-1">Description</label>
93	          <textarea value={form.description} onChange={(e) => setForm({ ...form, description: e.target.value })}
94	            className="w-full px-3 py-2 border rounded focus:ring-2 focus:ring-primary-500" rows={4} maxLength={5000} />
95	        </div>
96	        <div className="grid grid-cols-2 gap-4">
97	          <div>
98	            <label className="block text-sm font-medium text-gray-700 mb-1">Price (cents) *</label>
99	            <input type="number" value={form.price_cents} onChange={(e) => setForm({ ...form, price_cents: Number(e.target.value) })}
100	              className="w-full px-3 py-2 border rounded focus:ring-2 focus:ring-primary-500" required min={1} />
101	          </div>
102	          <div>
103	            <label className="block text-sm font-medium text-gray-700 mb-1">Currency</label>
104	            <input type="text" value={form.currency} onChange={(e) => setForm({ ...form, currency: e.target.value })}
105	              className="w-full px-3 py-2 border rounded" maxLength={3} />
106	          </div>
107	        </div>
108	        <div>
109	          <label className="block text-sm font-medium text-gray-700 mb-1">Image URL</label>
110	          <input type="url" value={form.image_url} onChange={(e) => setForm({ ...form, image_url: e.target.value })}
111	            className="w-full px-3 py-2 border rounded" />
112	        </div>
113	
114	        {!isEdit && (
115	          <>
116	            <div>
117	              <label className="block text-sm font-medium text-gray-700 mb-1">Contract Address</label>
118	              <input type="text" value={form.contract_address} onChange={(e) => setForm({ ...form, contract_address: e.target.value })}
119	                className="w-full px-3 py-2 border rounded font-mono text-sm" maxLength={42} />
120	            </div>
121	            <div>
122	              <label className="block text-sm font-medium text-gray-700 mb-1">Metadata URI</label>
123	              <input type="url" value={form.metadata_uri} onChange={(e) => setForm({ ...form, metadata_uri: e.target.value })}
124	                className="w-full px-3 py-2 border rounded" />
125	            </div>
126	            <div className="grid grid-cols-2 gap-4">
127	              <div>
128	                <label className="block text-sm font-medium text-gray-700 mb-1">Chain ID</label>
129	                <input type="number" value={form.chain_id || ''} onChange={(e) => setForm({ ...form, chain_id: Number(e.target.value) })}
130	                  className="w-full px-3 py-2 border rounded" min={1} placeholder="e.g. 1" />
131	              </div>
132	              <div>
133	                <label className="block text-sm font-medium text-gray-700 mb-1">Token ID</label>
134	                <input type="text" value={form.token_id} onChange={(e) => setForm({ ...form, token_id: e.target.value })}
135	                  className="w-full px-3 py-2 border rounded font-mono text-sm" placeholder="Auto-generated if empty" />
136	              </div>
137	            </div>
138	            <p className="text-xs text-gray-400">Chain ID and Token ID are required when Contract Address is provided, optional otherwise.</p>
139	          </>
140	        )}
141	
142	        {error && <div className="text-sm text-red-600 bg-red-50 p-2 rounded">{error}</div>}
143	
144	        <div className="flex gap-2">
145	          <button
146	            type="submit"
147	            disabled={createMutation.isPending || updateMutation.isPending || !form.title || !form.price_cents}
148	            className="px-6 py-2 bg-primary-600 text-white rounded hover:bg-primary-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
149	          >
150	            {createMutation.isPending || updateMutation.isPending
151	              ? (isEdit ? 'Updating...' : 'Creating...')
152	              : (isEdit ? 'Update' : 'Create Listing')}
153	          </button>
154	          <button type="button" onClick={() => navigate(-1)} className="px-6 py-2 bg-gray-100 rounded hover:bg-gray-200">Cancel</button>
155	        </div>
156	      </form>
157	    </div>
158	  );
159	}
