25	  });
26	
27	  useEffect(() => {
28	    if (data?.unread_count !== undefined) {
29	      setUnreadCount(data.unread_count);
30	    }
31	  }, [data, setUnreadCount]);
32	
33	  useEffect(() => {
34	    if (abData) {
35	      setAssignments(abData);
36	    }
37	  }, [abData, setAssignments]);
38	
39	  return (
40	    <div className="flex min-h-screen bg-gray-50">
