VALID_NOTIFICATION_STATES = {"pending", "delivered", "failed", "permanently_failed"}

NOTIFICATION_TRANSITIONS = {
    "pending": {"delivered", "failed"},
    "failed": {"delivered", "permanently_failed"},
    "delivered": set(),
    "permanently_failed": set(),
}


class TestNotificationLifecycle(unittest.TestCase):
    """Matches the notification lifecycle in service + worker + migration 009."""

    def test_all_states_recognized(self):
        self.assertEqual(
            set(NOTIFICATION_TRANSITIONS.keys()),
